={
  "model": "gpt-4o-mini",
  "temperature": 0,
  "messages": [
    {
      "role": "system",
      "content": "You are a job application email classifier. Analyze the email and return ONLY valid JSON with no markdown fences or explanation.

Return exactly:
{
  "isJobResponse": true/false,
  "company": "Company Name or null",
  "role": "Job Title or null",
  "status": "Applied|Assessment|Interview|Rejected|Offer|Other",
  "notes": "brief one-line summary"
}

Rules:
- isJobResponse = true ONLY if this email is from a real company/recruiter about a specific job the user applied to.
- Job alert blasts, newsletters, LinkedIn job digests = false.
- Confirmation emails (your application was received) = true, status = Applied.
- Rejection = Rejected. Interview invite = Interview. Task/assignment = Assessment."
    },
    {
      "role": "user",
      "content": "=From: {{ $json.from }}
Subject: {{ $json.subject }}
Body: {{ $json.body }}"
    }
  ]
}

parameters.jsCode:
const raw = $input.item.json.choices[0].message.content.trim();
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { isJobResponse: false, notes: 'Parse error: ' + raw.slice(0, 100) };
}

// Carry email metadata forward
const emailFields = $('Extract Email Fields').item.json;
return [{
  json: {
    isJobResponse: parsed.isJobResponse || false,
    company: parsed.company || null,
    role: parsed.role || null,
    status: parsed.status || 'Applied',
    notes: parsed.notes || '',
    from: emailFields.from,
    subject: emailFields.subject,
    emailDate: emailFields.date
  }
}];

// Store job data from AI before reading file
const jobData = $('Parse AI Response').item.json;
return [{ json: { jobData } }];

// Collect all existing rows
const allItems = $input.all();
let rows = allItems.map(item => item.json).filter(r => r['Company']);

// Get job data stored earlier
const jobData = $('Store Job Data').item.json.jobData;
const today = new Date().toISOString().split('T')[0];

const companyLower = (jobData.company || '').toLowerCase().trim();
const roleLower = (jobData.role || '').toLowerCase().trim();

// Try to find existing row (match by company + role)
const existingIdx = rows.findIndex(r =>
  (r['Company'] || '').toLowerCase().trim() === companyLower &&
  (r['Role'] || '').toLowerCase().trim() === roleLower
);

if (existingIdx >= 0) {
  // Update status of existing row
  rows[existingIdx]['Status'] = jobData.status;
  rows[existingIdx]['Last Updated'] = today;
  rows[existingIdx]['Notes'] = jobData.notes;
} else {
  // Add new row
  rows.push({
    'Company': jobData.company || 'Unknown',
    'Role': jobData.role || 'Unknown',
    'Status': jobData.status || 'Applied',
    'Date Applied': today,
    'Last Updated': today,
    'Sender': jobData.from || '',
    'Notes': jobData.notes || ''
  });
}

return rows.map(row => ({ json: row }));
